```python
def bubble_sort(arr):
    # Check if input is a list
    if not isinstance(arr, list):
        raise TypeError("Input must be a list.")

    # Handle empty or single-element lists
    if len(arr) <= 1:
        return arr.copy()

    # Check for None elements
    if any(item is None for item in arr):
        raise ValueError("List elements must not be None.")

    # Check that all elements are mutually comparable
    try:
        for i in range(len(arr)):
            for j in range(i + 1, len(arr)):
                _ = arr[i] <= arr[j]
    except TypeError:
        raise TypeError("List elements must be mutually comparable.")

    # Bubble sort algorithm
    result = arr.copy()
    n = len(result)
    for i in range(n):
        for j in range(0, n - i - 1):
            if result[j] > result[j + 1]:
                result[j], result[j + 1] = result[j + 1], result[j]
    return result

